**Recommendation:**

```js
const cors = require('cors');

app.use(cors({
  origin: ['https://your-app.example.com'], // explicit allowlist
  methods: ['GET', 'POST'],
  allowedHeaders: ['Content-Type', 'Authorization'],
}));
```

